// ============================================================
// NATIVE SHELL DETECTION (Capacitor) vs the website.
// On the website, relative "/api/..." calls reach Vercel as usual (API_BASE = "").
// Inside the iOS/Android app there is no local server, so those calls must be
// sent to the live site instead.
// ============================================================
const IS_NATIVE = typeof window !== "undefined" && (
  window.location.protocol === "capacitor:" ||
  window.location.protocol === "ionic:" ||
  !!(window.Capacitor && typeof window.Capacitor.isNativePlatform === "function" && window.Capacitor.isNativePlatform())
);
const API_BASE = IS_NATIVE ? "https://gotvero.com" : "";

// True on iOS — the native app (Capacitor) OR mobile Safari. Decides the sms: body separator
// below: iOS wants `sms:NUMBER&body=…`, Android/everything-else wants `sms:NUMBER?body=…`.
const IS_IOS = IS_NATIVE || (typeof navigator !== "undefined" && /iP(hone|ad|od)/.test(navigator.userAgent || ""));

// running-late-taptext: build an `sms:` deep link that PREFILLS the message body, so the barber's
// own Messages app opens addressed + pre-typed and THEY hit send. Nothing is sent by the system —
// this deliberately sidesteps SMS opt-out (a human texting from their own phone is not our automated
// marketing). Pure + platform-EXPLICIT (isIOS passed in, not read from globals) so it's unit-tested
// in tests/smslink.test.mjs against the exact iOS vs Android strings. US 10-digit numbers normalize
// to +1 E.164; an already-+ number passes through; an empty/garbage number returns "" so the caller
// can HIDE the link instead of building a broken `sms:`. The body is always encodeURIComponent'd so
// a "&", "?" or "#" in the copy can't corrupt the URL.
function smsLink(number, body, isIOS) {
  const raw = String(number == null ? "" : number).replace(/[^\d+]/g, "");
  const digits = raw.replace(/\D/g, "");
  if (!digits) return "";
  const to = raw[0] === "+" ? raw
    : digits.length === 10 ? "+1" + digits
    : (digits.length === 11 && digits[0] === "1") ? "+" + digits
    : digits;
  if (!body) return "sms:" + to;
  return "sms:" + to + (isIOS ? "&" : "?") + "body=" + encodeURIComponent(body);
}

// Fill the running-late template's tags for a self-sent text. REUSES the shop's saved wording
// (business.runningLate.message — the same copy the settings editor edits) so there's one source of
// truth for the message; falls back to a short default only if the shop cleared it. Handles the four
// tags the running-late editor documents: {client} {provider} {shop} {range} (+ {business} alias).
function runningLateText(business, { client, provider, range }) {
  const tpl = (business && business.runningLate && business.runningLate.message)
    || "Hi {client}, running about {range} min behind — see you soon!";
  const shop = (business && business.name) || "the shop";
  return String(tpl)
    .replace(/\{client\}/g, client || "there")
    .replace(/\{provider\}/g, provider || "your barber")
    .replace(/\{shop\}/g, shop)
    .replace(/\{business\}/g, shop)
    .replace(/\{range\}/g, String(range == null ? "" : range));
}

// review-taptext: a Google review request, self-sent the SAME way as running-late — opens the barber's
// OWN Messages pre-typed with the shop's saved review link, and they hit send. Nothing is automated, so
// it never touches SMS consent. Defaults ship so it works out of the box; owner edits link + wording in
// Settings → Google Reviews. Handles {client}/{first} (name) and {link}.
const DEFAULT_REVIEW_LINK = "https://g.page/r/CaFnft4o82oDEBE/review";
const DEFAULT_REVIEW_MESSAGE = "Hi {client}, I appreciate you coming in for your haircut! I was just wondering if you wouldn't mind leaving a super quick Google review? I'd really appreciate it. Here's the link just in case — thank you 🙏\n\n{link}";
const DEFAULT_REVIEW = { enabled: true, link: DEFAULT_REVIEW_LINK, message: DEFAULT_REVIEW_MESSAGE };
function reviewText(business, { client }) {
  const rv = (business && business.review) || {};
  const tpl = rv.message || DEFAULT_REVIEW_MESSAGE;
  const link = (rv.link != null && String(rv.link).trim() !== "") ? rv.link : DEFAULT_REVIEW_LINK;
  const first = client || "there";
  return String(tpl)
    .replace(/\{client\}/g, first)
    .replace(/\{first\}/g, first)
    .replace(/\{shop\}/g, (business && business.name) || "the shop")
    .replace(/\{link\}/g, link);
}

// visit-stamp: return the client with lastVisit advanced to this visit's date and visits bumped by one,
// so the rebook / overdue radar (which reads client.lastVisit + cadenceDays) builds from real checkouts.
// PURE + idempotency lives at the call site (gated on the appt not already being counted → visitCountedAt),
// so a reopened / re-paid ticket never double-counts. lastVisit only moves FORWARD, so checking out an old
// backfilled ticket can't rewind a newer visit. Unit-tested in tests/visit-stamp.test.mjs.
function stampVisitOnClient(c, appt) {
  const visitIso = (appt && appt.bookedFor) || new Date().toISOString();
  const advance = (!c || !c.lastVisit || new Date(visitIso) > new Date(c.lastVisit)) ? visitIso : c.lastVisit;
  return { ...c, lastVisit: advance, visits: (Number(c && c.visits) || 0) + 1, lastActivity: new Date().toISOString() };
}

// cadence-auto: derive a client's visit rhythm (avg days between visits) from their appointment
// history — the SAME formula the client card, checkout rhythm, and the importer already use — so the
// rebook / overdue radar (which reads client.cadenceDays) fires for clients who never had one set.
// Needs >=2 visits to form a gap; returns null below that so the caller keeps any existing cadence
// (never nulls one out). thisAppt is folded in because at checkout it may not yet read as past/done.
// Pure; unit-tested in tests/visit-stamp.test.mjs.
function deriveCadenceForClient(appts, clientId, thisAppt) {
  const now = Date.now();
  const ds = (appts || [])
    .filter((a) => a && a.clientId === clientId && a.bookedFor && a.status !== "cancelled" && a.status !== "block" && (new Date(a.bookedFor).getTime() < now || a.status === "done"))
    .map((a) => new Date(a.bookedFor).getTime());
  if (thisAppt && thisAppt.bookedFor) { const t = new Date(thisAppt.bookedFor).getTime(); if (!Number.isNaN(t) && !ds.includes(t)) ds.push(t); }
  ds.sort((a, b) => a - b);
  if (ds.length < 2) return null;
  let g = 0; for (let i = 1; i < ds.length; i++) g += (ds[i] - ds[i - 1]) / 86400000;
  return Math.max(1, Math.round(g / (ds.length - 1)));
}

// Native-only haptic tap (Capacitor Haptics). Dynamically imported like our other native plugins so
// the web bundle stays lean; a silent no-op on the web (Apple blocks web haptics) and never throws.
// The physical "tick" on a tap is what makes the installed app feel native rather than like a machine.
let _hapticImpact = null;
async function haptic(kind) {
  if (!IS_NATIVE) return;
  try {
    if (!_hapticImpact) {
      const { Haptics, ImpactStyle } = await import("@capacitor/haptics");
      _hapticImpact = (k) => Haptics.impact({ style: k === "medium" ? ImpactStyle.Medium : ImpactStyle.Light });
    }
    _hapticImpact(kind);
  } catch (e) { /* best-effort — haptics never block a tap */ }
}

// ---- ensureFreshSession ----------------------------------------------------
// iOS freezes Supabase's token-refresh timer whenever the app is backgrounded,
// so a staff login's access token can silently expire. Reopening the app then
// looks logged in, but the next DB write goes out with a dead token and Postgres
// rejects it with RLS error 42501. We call this right before each write: if a
// session exists and is at/near expiry, refresh it first. Purely additive — when
// there's no session it does nothing and never blocks a write, so it can't cause
// a regression on the (already-working) web side.
async function ensureFreshSession() {
  try {
    const { data } = await supabase.auth.getSession();
    const sess = data && data.session;
    if (!sess) return; // no auth session — leave existing behavior exactly as-is
    const expMs = (sess.expires_at || 0) * 1000; // expiry is unix-seconds
    if (Date.now() >= expMs - 60000) {           // refresh if expired or within 60s
      await supabase.auth.refreshSession();
    }
  } catch (e) { /* never let the guard itself block a write */ }
}
// cross-device-sync — staff table reads must refresh stale iOS tokens too. Writes already
// called ensureFreshSession; reads didn't, so iPad could cold-open with a dead JWT, fail the
// pull, show an empty calendar/clients, and never retry until a full sign-out.
async function fetchStaffTable(table, shopId, opts = {}) {
  const tries = Math.max(1, opts.tries || 3);
  // [staff-load-paginate] PostgREST caps a .select() at 1000 rows — an UNRANGED load silently dropped
  // every appt/client past the first 1,000 as the shop grew (clients already 2,900+). Worse: this is the
  // degraded fallback load, and a truncated appt set flowing into api/calendar-pull's delete step could
  // mass-DELETE synced/paid appointments beyond the cap. Page through EVERY row (stable .order("id"),
  // mirrors lib/paginate.js). NEVER return a partial set: any page error fails the whole load so the
  // retry re-fetches cleanly rather than handing a truncated list downstream.
  const fetchAll = async () => {
    const all = [];
    for (let from = 0, page = 0; page < 100000; page++, from += 1000) {
      const { data, error } = await supabase.from(table).select("data").eq("shop_id", shopId).order("id").range(from, from + 999);
      if (error) return { data: null, error };
      const batch = data || [];
      for (const r of batch) all.push(r);
      if (batch.length < 1000) return { data: all, error: null };
    }
    return { data: all, error: null };
  };
  let lastErr = null;
  for (let attempt = 0; attempt < tries; attempt++) {
    if (attempt > 0) await new Promise((r) => setTimeout(r, 800 * attempt));
    await ensureFreshSession();
    let { data, error } = await fetchAll();
    if (!error) return { data, error: null };
    lastErr = error;
    const msg = String((error && error.message) || error);
    const authish = /jwt|expired|401|42501|not authenticated/i.test(msg) || (error && error.code === "PGRST301");
    if (authish) {
      try { await supabase.auth.refreshSession(); } catch (e) {}
      await ensureFreshSession();
      ({ data, error } = await fetchAll());
      if (!error) return { data, error: null };
      lastErr = error;
    }
    const netish = /fetch|network|timeout|load failed/i.test(msg);
    if (!netish && !authish) break;
  }
  return { data: null, error: lastErr };
}

