// PHOTO LIBRARY — curated "looks" baked in for the prototype.
// In the live product this becomes a live Unsplash/Pexels feed.
// (Using Unsplash CDN URLs as stand-ins for the curated set.)
// ============================================================
const PHOTO_LIBRARY = {
  Haircuts: [
    "photo-1503951914875-452162b0f3f1", "photo-1599351431202-1e0f0137899a",
    "photo-1622286342621-4bd786c2447c", "photo-1605497788044-5a32c7078486",
  ],
  Beard: [
    "photo-1621607512214-68297480165e", "photo-1517832606299-7ae9b720a186",
    "photo-1635273051937-a0cc8b6e8e8e", "photo-1582893561942-d61adcb2e534",
  ],
  Shave: [
    "photo-1503951914875-452162b0f3f1", "photo-1493256338651-d82f7acb2b38",
    "photo-1599351431613-18ef1fdd09e3", "photo-1596728325488-58c87691e9af",
  ],
  Spa: [
    "photo-1570172619644-dfd03ed5d881", "photo-1596755389378-c31d21fd1273",
    "photo-1512290923902-8a9f81dc236c", "photo-1519823551278-64ac92734fb1",
  ],
};
const imgUrl = (id, w = 400) => (typeof id === "string" && (id.startsWith("data:") || id.startsWith("http"))) ? id : `https://images.unsplash.com/${id}?auto=format&fit=crop&w=${w}&q=70`;
// Portrait/headshot stand-ins for staff profile pictures.
const STAFF_PORTRAITS = [
  "photo-1622286342621-4bd786c2447c", "photo-1595959183082-7b570b7e08e2",
  "photo-1500648767791-00dcc994a43e", "photo-1494790108377-be9c29b29330",
  "photo-1607990281513-2c110a25bd8c", "photo-1544005313-94ddf0286df2",
  "photo-1568602471122-7832951cc4c5", "photo-1438761681033-6461ffad8d80",
  "photo-1507003211169-0a1dd7228f2d", "photo-1599566150163-29194dcaad36",
  "photo-1580489944761-15a19d654956", "photo-1534528741775-53994a69daeb",
];
// Guarantees a profile photo for any staff member: their own if set,
// otherwise a stable portrait derived from their id (never blank).
const hashStr = (str) => { let h = 0; const s = String(str || ""); for (let i = 0; i < s.length; i++) { h = (h * 31 + s.charCodeAt(i)) | 0; } return Math.abs(h); };
const staffPhoto = (p) => (p && p.photo) ? p.photo : STAFF_PORTRAITS[hashStr(p && p.id) % STAFF_PORTRAITS.length];
// Providers persist their display order in an `order` field. Postgres returns rows
// unordered, so we always re-sort on load — otherwise a reorder reverts on the next
// session/focus reload. "anyone" stays pinned first; missing order falls back to
// current array position so legacy data (no order yet) keeps its existing sequence.
// As-you-type US phone formatting: (503) 555-0142. Keeps only digits, caps at 10
// (drops a leading 1), and formats progressively so the field reads right while typing.
const formatPhone = (raw) => {
  let d = String(raw || "").replace(/\D/g, "");
  if (d.length === 11 && d[0] === "1") d = d.slice(1);
  d = d.slice(0, 10);
  if (d.length === 0) return "";
  if (d.length < 4) return "(" + d;
  if (d.length < 7) return `(${d.slice(0, 3)}) ${d.slice(3)}`;
  return `(${d.slice(0, 3)}) ${d.slice(3, 6)}-${d.slice(6)}`;
};
// Keep only digits (optionally one decimal point) for numeric fields.
const onlyDigits = (raw, decimal = false) => {
  const s = String(raw || "");
  return decimal ? s.replace(/[^\d.]/g, "").replace(/(\..*)\./g, "$1") : s.replace(/\D/g, "");
};
const sortProviders = (list) => {
  const arr = Array.isArray(list) ? list : [];
  return arr
    .map((p, i) => ({ p, i }))
    .sort((a, b) => {
      if (a.p.id === "anyone") return -1;
      if (b.p.id === "anyone") return 1;
      // DETERMINISTIC like byServiceOrder: primary key `order`, tiebreak on stable `id` — NOT the array
      // index. Staff with a missing/equal order (e.g. Dan+Heather, both order:undefined) used to fall back
      // to array position = the arbitrary DB return order, so their calendar columns/list could reshuffle
      // across loads (same class of bug as the menu-order one). The id tiebreak makes it stable.
      const ao = a.p.order ?? 1e9, bo = b.p.order ?? 1e9;
      return (ao - bo) || String(a.p.id ?? "").localeCompare(String(b.p.id ?? ""));
    })
    .map(({ p }) => p);
};
// Map a staff login email to a provider row. Shop cards often carry the shared inbox while
// owners sign in with personal Gmail (michaelsdan415@…) — hint from the address before @.
const resolveAuthStaff = (authEmail, staff) => {
  if (!authEmail || !staff || !staff.length) return null;
  const norm = (e) => (e || "").trim().toLowerCase();
  const cur = norm(authEmail);
  const loginHint = cur.split("@")[0] || "";
  const emailMatches = staff.filter((p) => norm(p.email) && norm(p.email) === cur);
  if (emailMatches.length === 1) return emailMatches[0];
  if (emailMatches.length > 1) return emailMatches.find((p) => p.pulseRole === "owner") || emailMatches[0];
  return staff.find((p) => {
    const n = (p.name || "").trim().toLowerCase().split(/\s+/)[0];
    const id = String(p.id || "").toLowerCase();
    return (n && loginHint.includes(n)) || (id && loginHint.includes(id));
  }) || staff.find((p) => p.pulseRole === "owner") || null;
};
// GUARD: owner-access-fail-safe. The Settings tab + owner powers hang off isOwner, which is read from
// the providers list. The sanitized get_public_providers feed OMITS pulseRole, so if a signed-in owner
// transiently loads that feed, the list contains NO owner and Settings silently disappears (the
// "my Settings vanished" bug). Rule: a feed that DOES contain an owner is trustworthy — honor it exactly
// (a barber still resolves to non-owner). A feed with NO owner at all is degraded, not proof the user
// isn't one, so it must not REVOKE a previously-confirmed owner. Pure + unit-tested so it can't drift.
function ownerAccessResilient(liveIsOwner, anyOwnerInFeed, wasConfirmedOwner) {
  if (liveIsOwner) return true;                          // the load positively identifies an owner
  if (!anyOwnerInFeed && wasConfirmedOwner) return true; // degraded feed can't strip a confirmed owner
  return false;                                          // healthy feed + not an owner → not an owner
}
// Clients keep their colored initial unless a photo has been set explicitly.
const clientPhoto = (c) => (c && c.photo) ? c.photo : null;
// Reusable circular avatar — edge-to-edge photo or centered initial.
// Renders identically everywhere so staff/client avatars never break.
function Avatar({ size = 42, photo = null, initial = "", color = "var(--gold)", fontSize, style = {}, children }) {
  const fs = fontSize || Math.round(size * 0.44);
  const base = color || "var(--gold)";
  return (
    <div style={{ width: size, height: size, borderRadius: "50%", overflow: "hidden", flexShrink: 0, position: "relative", background: photo ? "var(--panel2)" : base, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Fraunces', serif", fontWeight: 500, fontSize: fs, ...style }}>
      {photo
        ? <img src={imgUrl(photo, Math.max(120, size * 3))} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
        : (initial || null)}
      {children}
    </div>
  );
}
// One back control for the whole app — quiet gray chevron + the name of where you'll land.
// Usage:  <BackBar to="Pulse" onClick={() => setPulseDetail(null)} />
function BackBar({ to = "Back", onClick, style }) {
  return (
    <button onClick={onClick} style={{ background: "none", border: "none", color: "var(--sub)", display: "flex", alignItems: "center", gap: 4, fontSize: 14.5, fontFamily: "'Jost', sans-serif", padding: 0, cursor: "pointer", marginBottom: 18, ...style }}>
      <ChevronLeft size={18} /> {to}
    </button>
  );
}
const ALL_LIBRARY = Object.entries(PHOTO_LIBRARY).flatMap(([cat, ids]) => ids.map((id) => ({ id, cat })));

