// One-time refresh of the five client-facing reminder templates to the current welcoming copy.
// Version-guarded so a shop's own later edits in Settings → Messages are never clobbered: once
// msgCopyVersion reaches MSG_COPY_VERSION the migration is a no-op. Only the listed ids are touched
// (label/timing/body); channel and every other message are left exactly as the shop has them.
const MSG_COPY_VERSION = 8;
function migrateMessageCopy(biz) {
  try {
    if (!biz || (biz.msgCopyVersion || 0) >= MSG_COPY_VERSION) return biz;
    const def = Object.fromEntries((DEFAULT_BUSINESS.messages || []).map((m) => [m.id, m]));
    const base = (Array.isArray(biz.messages) && biz.messages.length) ? biz.messages : DEFAULT_BUSINESS.messages;
    let messages = base.slice();
    // v2: one-time refresh of the five client reminder templates to current copy (only below v2).
    if ((biz.msgCopyVersion || 0) < 2) {
      const ids = ["booked", "remind2d", "remind24h", "remind3h", "checkin"];
      messages = messages.map((m) => (ids.includes(m.id) && def[m.id]) ? { ...m, label: def[m.id].label, timing: def[m.id].timing, body: def[m.id].body } : m);
      ids.forEach((id) => { if (!messages.some((m) => m.id === id) && def[id]) messages.push(def[id]); });
    }
    // v3: make sure the birthday message template exists (additive — never clobbers edits).
    if (!messages.some((m) => m.id === "birthday") && def.birthday) messages.push(def.birthday);
    // v4: swap long dashes (U+2014) for normal dashes in every message body. A long dash forces
    //     a text into a costlier 70-char-per-message encoding; this roughly halves SMS cost. Any
    //     custom wording the shop wrote is preserved — only the dash character changes.
    if ((biz.msgCopyVersion || 0) < 4) {
      messages = messages.map((m) => (m && typeof m.body === "string" && m.body.indexOf("—") !== -1) ? { ...m, body: m.body.replace(/—/g, "-") } : m);
    }
    // v5: refresh ONLY the 15-minute check-in body to the shorter, warmer copy (greets the client,
    //     one SMS segment). The arrival instruction now comes from the {checkin link} tag itself,
    //     so the old typed "Here already? Let us know:" line is dropped. Only `checkin`'s body is
    //     touched — channel and every other message stay exactly as the shop has them.
    if ((biz.msgCopyVersion || 0) < 5) {
      messages = messages.map((m) => (m && m.id === "checkin" && def.checkin) ? { ...m, body: def.checkin.body } : m);
    }
    // v6: drop the "Missed / Late Cancellation" (no-show) template. It was never wired to send —
    // a dead toggle. The owner charges no-show fees silently from the dashboard and does not want
    // any no-show notice or auto-receipt going to clients, so the setting is removed entirely.
    if ((biz.msgCopyVersion || 0) < 6) {
      messages = messages.filter((m) => m && m.id !== "noshow");
    }
    // v7: the "Slot Opened" offer used to say "Reply YES to grab it" — but there's no reply-YES
    //     handler; openings book first-come via a link. Refresh that one body to the current
    //     first-come copy (with a {book link}) ONLY if the shop hasn't customized it, so the
    //     editable template matches what actually gets sent. Any custom wording is preserved.
    if ((biz.msgCopyVersion || 0) < 7) {
      const staleWaitlist = "Good news {client} - a spot opened for your {service} with {provider} on {date} at {time}. Reply YES to grab it before someone else does!";
      messages = messages.map((m) => (m && m.id === "waitlist" && m.body === staleWaitlist && def.waitlist) ? { ...m, body: def.waitlist.body, channel: def.waitlist.channel } : m);
    }
    // v8: the "Deposit Received" message never actually fired (audit #14) and was worded as a
    //     partial deposit — wrong for a pay-in-full prepay (audit #7). Now it's a general payment
    //     receipt that fires whenever money is taken at booking. Refresh label/timing/body/channel
    //     ONLY if the shop still has the old default, so any custom wording is preserved.
    if ((biz.msgCopyVersion || 0) < 8) {
      const staleDeposit = "Thanks {client}! We've received your deposit for your {service} with {provider} on {date} at {time}. It goes toward your total - see you at {business}.";
      messages = messages.map((m) => (m && m.id === "deposit" && m.body === staleDeposit && def.deposit) ? { ...m, label: def.deposit.label, timing: def.deposit.timing, body: def.deposit.body, channel: def.deposit.channel } : m);
    }
    return { ...biz, messages, msgCopyVersion: MSG_COPY_VERSION };
  } catch (e) { return biz; }
}

// Each working day: { on: bool, start: minutes, end: minutes }. Keyed 0(Sun)–6(Sat).
const DEFAULT_HOURS = {
  0: { on: true, start: 600, end: 900 },   // Sun 10–3
  1: { on: true, start: 540, end: 1020 },  // Mon 9–5
  2: { on: false, start: 540, end: 1020 }, // Tue off
  3: { on: false, start: 540, end: 1020 }, // Wed off
  4: { on: true, start: 540, end: 1020 },  // Thu 9–5
  5: { on: true, start: 540, end: 1020 },  // Fri 9–5
  6: { on: true, start: 540, end: 1020 },  // Sat 9–5
};

// Resolve a barber's working hours for a specific date: a one-off per-date override wins,
// otherwise their recurring weekly schedule for that weekday. Returns { on, start, end } | null.
function hoursForDate(prov, date) {
  if (!prov || !date) return null;
  const key = date.getFullYear() + "-" + date.getMonth() + "-" + date.getDate();
  const ov = prov.hoursOverrides && prov.hoursOverrides[key];
  if (ov) return ov;
  return (prov.hours || {})[date.getDay()] || null;
}
// Canonical per-date key (matches hoursForDate / applyHours: Y-M-D, no zero-pad).
const dateKey = (d) => { const x = new Date(d); return x.getFullYear() + "-" + x.getMonth() + "-" + x.getDate(); };
// effectiveHours is the shared reader: a one-off date override wins over the weekly
// shift. Delegates to hoursForDate so the staff editor, booking availability, and the
// calendar all read the same source.
const effectiveHours = (p, date) => hoursForDate(p, new Date(date));
const defaultStaffNotifications = () => ({ smsOnlineBooking: true, smsOtherBooking: true, emailOnlineBooking: false, appNewText: true, appNewChat: true, appMissedCall: true });
const defaultComp = () => ({
  service: { on: false, type: "basic", basicPct: 0, tiers: [{ upTo: 500, pct: 30 }, { upTo: null, pct: 40 }] },
  product: { on: false, defaultPct: 0, overridesOn: false },
  hourly: { on: false, rate: 0, greaterOf: false },
});

