const defaultPermissions = (userType) => {
  const on = userType === "Admin";
  const m = {};
  ALL_PERMISSION_KEYS.forEach((k) => { m[k] = on; });
  return m;
};
const countPermsOn = (perms) => ALL_PERMISSION_KEYS.reduce((n, k) => n + ((perms && perms[k]) ? 1 : 0), 0);

