const THEME_CATS = ["Crisp & Minimal", "Bold & Sleek"];
const THEME_IDS = THEMES.map((t) => t.id);
// The app-wide default theme — used for new shops, as the final fallback when no valid theme is
// set, and on the pre-auth staff-login screen (which must not inherit a saved dark shop theme).
const DEFAULT_THEME = "steel";
const buildThemeCSS = () => THEMES.map((th) => {
  const v = th.t;
  const grad = th.grad || `linear-gradient(135deg,${v.gold},${v.gold})`;
  // --tint / --tint2 = the subtle "highlight/selected" FILL behind accented rows & cards.
  // In colorful themes it's a gentle gold wash; in the strict black-&-white "studio"
  // theme it collapses to pure white so highlights never read as grey.
  const tint = ["studio", "onyx"].includes(th.id) ? v.panel : `color-mix(in srgb, ${v.gold} 10%, ${v.panel})`;
  const tint2 = ["studio", "onyx"].includes(th.id) ? v.panel2 : `color-mix(in srgb, ${v.gold} 14%, ${v.panel2})`;
  // --wash = translucent accent behind icon circles / selected pills / badges. Studio = fully
  // transparent (clean white, black icons/text, black-outlined selection) so nothing reads grey;
  // colored themes keep a soft gold wash.
  const wash = ["studio", "onyx"].includes(th.id) ? "transparent" : `color-mix(in srgb, ${v.gold} 13%, transparent)`;
  // Studio (strict B&W): override the shadow tier so every card/sheet/panel that uses
  // var(--shadow-sm/lg) lifts off the white page with one soft, consistent shadow.
  // Set on the theme class (which sits on #app-root) so the whole subtree inherits it;
  // the other 11 themes fall through to the default :root shadows, untouched.
  const studioShadows = ["studio", "onyx"].includes(th.id)
    ? "--shadow-sm:0 1px 2px rgba(0,0,0,.06), 0 8px 22px rgba(0,0,0,.08);--shadow-lg:0 4px 12px rgba(0,0,0,.08), 0 18px 44px rgba(0,0,0,.12);--shadow-md:0 2px 6px rgba(0,0,0,.06), 0 10px 28px rgba(0,0,0,.09);"
    : "";
  return `.theme-${th.id}{--bg:${v.bg};--canvas:${th.canvas || v.bg};--grain:${th.grain || 0};--grain-blend:${th.dark ? "overlay" : "multiply"};--panel:${v.panel};--panel2:${v.panel2};--tint:${tint};--tint2:${tint2};--wash:${wash};--line:${v.line};--border:${v.border};--border2:${v.border2};--text:${v.text};--text2:${v.text2};--sub:${v.sub};--faint:${v.faint};--gold:${v.gold};--gold-grad:${grad};--on-gold:${v.onGold};--live:${v.live || v.gold};--shadow:${v.shadow};--overlay:${v.overlay};${studioShadows}--font-disp:${th.disp};--font-body:${th.body};}` + (th.id === "onyx" ? `\n.theme-onyx, .theme-onyx *{font-family:'Hanken Grotesk', sans-serif !important;}` : "");
}).join("\n");

// Portal: render full-screen overlays. Without react-dom we can't truly portal,
// so we render inline but pin to the viewport with position:fixed + max z-index.
// The overlay wrapper itself carries NO transform (so it anchors to the viewport,
// not a transformed ancestor); inner content keeps the drop animation.
function Portal({ children }) {
  // Render into <body> so a transformed / backdrop-filtered ancestor (the dashboard
  // header) can't trap our position:fixed overlay and squeeze it below the app chrome.
  if (typeof document === "undefined") return null;
  return createPortal(children, document.body);
}

// Sheet: a popup that opens centered in the viewport, never off-screen.
function Sheet({ open, onClose, children, align = "top", maxWidth = 520 }) {
  useEffect(() => {
    if (!open) return;
    const prev = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = prev; };
  }, [open]);
  if (!open) return null;
  const justify = align === "bottom" ? "flex-end" : align === "top" ? "flex-start" : "center";
  // Animate from the correct edge: bottom slides up, center pops, top/default drops down (shared .appt-drop).
  const animClass = align === "bottom" ? "sheet-up" : align === "center" ? "sheet-pop" : "appt-drop";
  // The outer flex container fills the screen; the inner box is capped and its body scrolls.
  // Rendered through a portal to document.body so a transformed ancestor (animations) can't
  // trap the position:fixed overlay and cut off scrolling.
  return createPortal((
    <div onClick={onClose} className="sheet-overlay" style={{ position: "fixed", top: 0, left: 0, right: 0, height: "100dvh", background: "var(--overlay)", backdropFilter: "blur(3px) saturate(1.08)", WebkitBackdropFilter: "blur(3px) saturate(1.08)", zIndex: 2000, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: justify, padding: align === "center" ? "20px" : "0", boxSizing: "border-box" }}>
      <div onClick={(e) => e.stopPropagation()} className={animClass} style={{
        width: "100%", maxWidth, background: "var(--bg)",
        borderRadius: align === "top" ? "0 0 22px 22px" : (align === "center" ? 22 : "22px 22px 0 0"),
        paddingTop: align === "top" ? "calc(env(safe-area-inset-top) + 16px)" : 20,
        maxHeight: align === "center" ? "85dvh" : "92dvh",
        display: "flex", flexDirection: "column",
        boxShadow: "0 20px 60px rgba(0,0,0,0.4)", boxSizing: "border-box", overflow: "hidden",
      }}>
        {align === "bottom" && <div aria-hidden="true" style={{ width: 38, height: 4, borderRadius: 3, background: "var(--border2)", margin: "0 auto 12px", flexShrink: 0 }} />}
        <div style={{
          overflowY: "auto", WebkitOverflowScrolling: "touch", overscrollBehavior: "contain",
          padding: "0 20px calc(24px + env(safe-area-inset-bottom))",
          minHeight: 0, flex: 1,
        }}>
          {children}
        </div>
      </div>
    </div>
  ), document.body);
}

// Tap-to-call / Tap-to-text: render a phone number as a subtle button that opens a Sheet with Call + Text options.
// Both buttons use native `tel:` and `sms:` URIs so mobile opens the dialer / Messages directly.
// Format a US phone for display: 5038402389 -> (503) 840-2389. Leaves non-standard numbers as-is.
function fmtPhone(number) {
  if (!number) return "";
  let d = String(number).replace(/\D/g, "");
  if (d.length === 11 && d[0] === "1") d = d.slice(1);     // drop US country code
  if (d.length === 7) d = "503" + d;                        // 7-digit → default to shop area code
  if (d.length === 10) return `(${d.slice(0, 3)}) ${d.slice(3, 6)}-${d.slice(6)}`;
  return String(number);                                    // malformed → show as-is, never mangle
}
// ---- Stripe (client side) ----
// The publishable key is meant to be public and safe to ship in the app bundle.
// The SECRET key lives only in Vercel (env var) and is used by /api/stripe — never here.
const STRIPE_PUBLISHABLE_KEY = "pk_live_51TdVev0XV9TtWHCqYNf2SU6kjZXGqGXGp2hSyjKzpbPWFgboCljXllRK9nJ4tESrSnhe6Rp82iGzyPyk7FxVzZCY00sZKQupPQ";
let _stripePromise = null;
function getStripe() {
  if (_stripePromise) return _stripePromise;
  _stripePromise = new Promise((resolve) => {
    if (typeof window === "undefined") { resolve(null); return; }
    if (window.Stripe) { resolve(window.Stripe(STRIPE_PUBLISHABLE_KEY)); return; }
    const el = document.createElement("script");
    el.src = "https://js.stripe.com/v3/";
    el.async = true;
    el.onload = () => resolve(window.Stripe ? window.Stripe(STRIPE_PUBLISHABLE_KEY) : null);
    el.onerror = () => resolve(null);
    document.head.appendChild(el);
  });
  return _stripePromise;
}
// ---- Idempotency for money-moving actions ----------------------------------
// A retried charge/refund (e.g. the response was lost on a flaky connection)
// must never move money twice. Each logical operation gets a stable key, reused
// while the operation is still outstanding so Stripe collapses duplicates. The
// key is derived from the operation's parameters (card / payment-intent + the
// exact amount) so two genuinely different amounts never collide. We rotate the
// key as soon as the server gives a DEFINITIVE answer (a clean success, or a
// real 4xx like a card decline — money didn't move), and keep it only when the
// network never answered (a 5xx or no response) — exactly the case where a
// blind retry could otherwise double up.
const _idemKeys = new Map(); // sig -> { key, ts }
// #14: a retained key must not live forever. Reuse it only briefly, so a genuine retry of an uncertain
// charge stays idempotent (a few seconds later) but two legitimately-separate identical charges of the
// same client in one long-lived session (e.g. an all-day front-desk iPad) never share a key and swallow
// the second. A definitive server answer still rotates the key immediately (see stripeApi below).
const IDEM_TTL_MS = 600000; // 10 minutes — far longer than any real retry, far shorter than a session
const newIdemKey = () => { try { return crypto.randomUUID(); } catch (e) { return Date.now().toString(36) + Math.random().toString(36).slice(2); } };
const idemKeyFor = (sig) => {
  const now = Date.now();
  const cur = _idemKeys.get(sig);
  if (cur && (now - cur.ts) < IDEM_TTL_MS) return cur.key;
  const key = newIdemKey();
  _idemKeys.set(sig, { key, ts: now });
  return key;
};
const idemSig = (p) => {
  const cents = Math.round((Number(p.amount) || 0) * 100);
  if (p.action === "charge") return `charge:${p.customerId}:${p.paymentMethodId}:${cents}`;
  if (p.action === "refund") return `refund:${p.paymentIntentId}:${cents}`;
  return null; // setup / sale_intent: no server-side double-charge to guard
};

// [outage-honest-menu] Race any Supabase/async call against a timeout so a HANGING backend
// (compute-exhausted outage: the request never resolves OR rejects) rejects like a normal
// failure instead of leaving a spinner spinning forever. Callers' existing try/catch then
// treats a hang exactly like a clean error → the honest error state — never an endless
// "loading"/"confirming". 20s is far longer than any healthy call, short enough to fail
// honestly during an outage. Root-cause fix for the whole no-timeout hang class.
const RPC_TIMEOUT_MS = 20000;
// Best-effort pre-booking RPCs (dedup lookups + the belt-and-suspanders client save that
// runs BEFORE book_public) get a tighter budget: they're not the durable write (book_public
// is), so a hang here must fail FAST and let the booking proceed to its own honest-error
// timeout — otherwise the submit stalls on the earliest hang and never reaches book_public.
const PREBOOK_RPC_TIMEOUT_MS = 8000;
function withRpcTimeout(promise, ms = RPC_TIMEOUT_MS) {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error("timed out — backend unreachable")), ms)),
  ]);
}

// Build JSON request headers with the signed-in user's token attached, for
// owner-only server endpoints (e.g. /api/calendar-pull) that must reject
// anonymous callers. When there's no session the Authorization header is simply
// omitted — harmless for any endpoint that doesn't require it.
async function authedHeaders() {
  await ensureFreshSession();
  const headers = { "Content-Type": "application/json" };
  try {
    const { data: sess } = await supabase.auth.getSession();
    const token = sess && sess.session && sess.session.access_token;
    if (token) headers.Authorization = `Bearer ${token}`;
  } catch (e) {}
  return headers;
}

// The shop this browser/app is currently acting for (the subdomain/path-derived
// SHOP_ID). Set once App resolves it; read by stripeApi (money-out calls name
// their shop so the server can verify staff membership) and by the /api/notify
// callers (so the server can bind a send to a recipient on file for this shop).
let _stripeShop = null;

// Call our serverless Stripe function. Throws with a readable message on failure.
// Money-moving actions (charge / refund) are staff-only on the server, so we
// attach the signed-in staff member's token when there is a session. Public
// booking calls (setup / sale_intent) run without a session — no token is
// sent and the server leaves those actions open, so the booking flow is
// unaffected.
async function stripeApi(payload) {
  const headers = { "Content-Type": "application/json" };
  try {
    const { data: sess } = await supabase.auth.getSession();
    const token = sess && sess.session && sess.session.access_token;
    if (token) headers.Authorization = `Bearer ${token}`;
  } catch (e) {}
  const sig = idemSig(payload);
  const withShop = _stripeShop ? { ...payload, shop: _stripeShop } : payload;
  const body = sig ? { ...withShop, idempotencyKey: idemKeyFor(sig) } : withShop;
  let r;
  try {
    // [outage-honest-menu] Timeout the payment call so a HANGING backend (compute-exhausted: never
    // resolves or rejects) surfaces the honest "couldn't reach the payment server" error instead of a
    // charge spinner that never ends. The idempotency key is KEPT on this path (outcome unknown), so a
    // retry of a charge that actually landed reuses the same key → Stripe dedupes → never a double charge.
    r = await withRpcTimeout(fetch(API_BASE + "/api/stripe", { method: "POST", headers, body: JSON.stringify(body) }));
  } catch (netErr) {
    // No response at all (or timed out) — outcome unknown. Keep the key so a retry is idempotent.
    throw new Error("Couldn't reach the payment server — check your connection and try again.");
  }
  let data = {};
  try { data = await r.json(); } catch (e) {}
  // Definitive answer = a 2xx, or a 4xx (decline / bad request / not authorized) where money did not move.
  // A 5xx is NOT definitive, so we hold the key for an idempotent retry.
  const definitive = r.ok || (r.status >= 400 && r.status < 500);
  if (sig && definitive) _idemKeys.delete(sig);
  if (!r.ok || data.error) throw new Error(data.error || `Request failed (${r.status})`);
  return data;
}

// Money-safety (sale-recover-succeeded): a charge whose confirm SUCCEEDED on Stripe but whose
// response was lost to a dropped network leaves a held clientSecret pointing at an ALREADY-PAID
// intent. Given that secret, return the succeeded intent's id so the caller records it as paid
// WITHOUT charging again; return null if it hasn't succeeded (safe to charge/clear as before).
// Never throws — a failed lookup (still offline) just falls through to the normal path.
async function recoverSucceededIntent(stripe, clientSecret) {
  try {
    if (!stripe || !clientSecret) return null;
    const r = await stripe.retrievePaymentIntent(clientSecret);
    const pi = r && r.paymentIntent;
    if (pi && pi.status === "succeeded") return pi.id;
  } catch (e) {}
  return null;
}

// ---- Durable payment outbox (money-safety: outbox-payment-durable) ---------------------------------
// A sale's ledger record is what stops a reopened ticket from re-charging (paidForAppt reads it). If
// that write fails — bad network, a transient server error, the app killed right after — the record
// would live only in memory and vanish on reload, and the ticket would look unpaid. This keeps a TINY
// copy in localStorage (never photos) until the write is CONFIRMED on the server, re-attempting on
// load, on reconnect, and on an interval. Idempotent: keyed by the payment record id, so re-applying a
// sale already saved is a no-op and can never double-count.
function _payOutboxKey() { return `vero_pay_outbox_${_shopIdFromUrl() || ""}`; }
function payOutboxRead() {
  try { const raw = localStorage.getItem(_payOutboxKey()); const v = raw ? JSON.parse(raw) : []; return Array.isArray(v) ? v : []; } catch (e) { return []; }
}
function payOutboxWrite(list) {
  try { localStorage.setItem(_payOutboxKey(), JSON.stringify((Array.isArray(list) ? list : []).slice(-200))); } catch (e) {}
}
function payOutboxAdd(entry) {
  if (!entry || !entry.id || !entry.clientId || !entry.rec) return;
  const box = payOutboxRead();
  if (box.some((e) => e.id === entry.id)) return; // idempotent by record id
  box.push({ id: entry.id, clientId: entry.clientId, apptId: entry.apptId || null, rec: entry.rec, ts: entry.ts || 0 });
  payOutboxWrite(box);
}
// Ledger recs still pending for an appointment (not already counted in its known ledger). Folded into
// paidForAppt/paidTowardItems so a reopen credits/blocks correctly even before the drain re-injects.
function payOutboxRecsForAppt(apptId, ledgerIds) {
  if (!apptId) return [];
  const seen = ledgerIds instanceof Set ? ledgerIds : new Set();
  return payOutboxRead().filter((e) => e.apptId === apptId && !seen.has(e.id)).map((e) => e.rec).filter(Boolean);
}
function payOutboxHasAppt(apptId) { return !!apptId && payOutboxRead().some((e) => e.apptId === apptId); }

// Real card entry. In Live it mounts Stripe Elements and charges/saves for real;
// in Test it's a safe simulation that touches no processor and charges nothing.
// mode: "payment" (charge `amount` dollars) | "setup" (save a card, no charge).
function StripeCardSheet({ live, mode, amount, totalDue, clientName, clientEmail, clientPhone, onClose, onDone }) {
  const isPay = mode === "payment" && Number(amount) > 0;
  const [phase, setPhase] = useState("entry"); // entry | done
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const [result, setResult] = useState(null);
  const [ready, setReady] = useState(false); // true once the secure card field is mounted & tappable
  const [wallet, setWallet] = useState(false); // true once an Apple Pay / Google Pay button is available & mounted
  const [walletChecking, setWalletChecking] = useState(true); // true while canMakePayment() is still resolving — holds the wallet slot so Apple Pay never pops in late
  const cardBox = useRef(null);
  const prBox = useRef(null);
  const els = useRef(null);
  // GUARD: sale-intent-idempotent — one deposit PaymentIntent per amount, reused across retries (manual
  // card AND wallet) so a retry after a dropped/uncertain response re-confirms the same intent instead
  // of double-charging the booking deposit.
  const saleRef = useRef({ clientSecret: null, cents: null });

  useEffect(() => {
    setReady(false);
    let dead = false;
    (async () => {
      const stripe = await getStripe();
      if (dead) return;
      if (!stripe || !cardBox.current) { setErr("Couldn't load the secure card field. Refresh and try again."); setWalletChecking(false); return; }
      const elements = stripe.elements();
      const card = elements.create("card", { style: { base: { fontSize: "16px", color: "#232221", fontFamily: "'Jost', sans-serif", "::placeholder": { color: "#A39C8A" } }, invalid: { color: "#B5564B" } } });
      card.mount(cardBox.current);
      card.on("ready", () => { if (!dead) setReady(true); });
      card.on("change", (ev) => setErr(ev.error ? ev.error.message : ""));
      els.current = { stripe, card };

      // Apple Pay / Google Pay for BOTH paths: charging an amount, or saving a card on
      // file with no charge (a $0 "pending" total). The button only appears when the
      // browser/device actually supports a wallet (Safari+Apple, Chrome+Google) on our
      // verified domain — everywhere else canMakePayment() is null and the card field
      // is the fallback, so this never breaks anyone who can't use it.
      // TEST MODE: no wallet button at all. A wallet charge is real money the instant it's
      // confirmed — there's no safe "simulate" for Apple Pay — so we simply don't offer it
      // when payments are in test mode. The card field below stays, and its submit is
      // simulated. This keeps "test mode — no real charge yet" honest.
      if (!live) { if (!dead) setWalletChecking(false); }
      else try {
        const pr = stripe.paymentRequest({
          country: "US", currency: "usd",
          total: isPay
            ? { label: "Booking deposit", amount: Math.round(Number(amount) * 100) }
            : { label: "Card on file — held to reserve", amount: 0, pending: true },
          requestPayerName: true, requestPayerEmail: true,
        });
        const prButton = elements.create("paymentRequestButton", { paymentRequest: pr, style: { paymentRequestButton: { type: "default", theme: "dark", height: "48px" } } });
        const can = await pr.canMakePayment();
        if (can && !dead && prBox.current) { prButton.mount(prBox.current); setWallet(true); els.current.prButton = prButton; }
        if (!dead) setWalletChecking(false);
        pr.on("paymentmethod", async (ev) => {
          try {
            if (isPay) {
              const dCents = Math.round(Number(amount) * 100);
              // sale-recover-succeeded: an already-succeeded deposit intent (dropped response) settles as paid.
              if (saleRef.current.clientSecret && saleRef.current.cents === dCents) {
                const recId = await recoverSucceededIntent(stripe, saleRef.current.clientSecret);
                if (recId) { ev.complete("success"); if (!dead) { setResult({ paid: true, intentId: recId, last4: null, brand: null }); setPhase("done"); } return; }
              }
              let dSecret = saleRef.current.clientSecret && saleRef.current.cents === dCents ? saleRef.current.clientSecret : null;
              if (!dSecret) {
                const intent = await stripeApi({ action: "sale_intent", amount: Number(amount), description: "Booking deposit" });
                if (!intent.clientSecret) { ev.complete("fail"); setErr(intent.error || "Couldn't start the charge."); return; }
                dSecret = intent.clientSecret; saleRef.current = { clientSecret: dSecret, cents: dCents };
              }
              const conf = await stripe.confirmCardPayment(dSecret, { payment_method: ev.paymentMethod.id }, { handleActions: false });
              if (conf.error) { ev.complete("fail"); setErr(conf.error.message || "Payment failed."); return; }
              ev.complete("success");
              if (conf.paymentIntent && conf.paymentIntent.status === "requires_action") {
                const again = await stripe.confirmCardPayment(dSecret);
                if (again.error) { setErr(again.error.message || "Payment needs another step."); return; }
              }
              const c4 = (ev.paymentMethod && ev.paymentMethod.card) || {};
              if (!dead) { setResult({ paid: true, intentId: conf.paymentIntent.id, last4: c4.last4 || "••••", brand: c4.brand }); setPhase("done"); }
            } else {
              // Save the wallet card on file — no charge now.
              const setup = await stripeApi({ action: "setup", customerId: null, name: clientName, email: clientEmail, phone: clientPhone });
              if (!setup.clientSecret) { ev.complete("fail"); setErr(setup.error || "Couldn't set up the card."); return; }
              const conf = await stripe.confirmCardSetup(setup.clientSecret, { payment_method: ev.paymentMethod.id }, { handleActions: false });
              if (conf.error) { ev.complete("fail"); setErr(conf.error.message || "Couldn't save the card."); return; }
              ev.complete("success");
              if (conf.setupIntent && conf.setupIntent.status === "requires_action") {
                const again = await stripe.confirmCardSetup(setup.clientSecret);
                if (again.error) { setErr(again.error.message || "Card needs another step."); return; }
              }
              const c4 = (ev.paymentMethod && ev.paymentMethod.card) || {};
              if (!dead) { setResult({ saved: true, pmId: ev.paymentMethod.id, stripeCustomerId: setup.customerId, last4: c4.last4 || "••••", brand: c4.brand }); setPhase("done"); }
            }
          } catch (e2) { try { ev.complete("fail"); } catch (_) {} setErr(e2.message || "Something went wrong. Try the card field."); }
        });
      } catch (e) { if (!dead) setWalletChecking(false); /* wallet unavailable — card field remains */ }

      // Fallback: if the 'ready' event is ever missed, enable the button shortly after mount.
      setTimeout(() => { if (!dead) setReady(true); }, 1200);
    })();
    return () => { dead = true; try { els.current && els.current.card.unmount(); } catch (e) {} try { els.current && els.current.prButton && els.current.prButton.unmount(); } catch (e) {} };
  }, []);

  const close = () => { setBusy(false); onClose && onClose(); };

  const submit = async () => {
    if (busy) return;
    setErr(""); setBusy(true);
    try {
      const e = els.current;
      if (!e) { setErr("The card field isn't ready yet — give it a second."); setBusy(false); return; }
      const pm = await e.stripe.createPaymentMethod({ type: "card", card: e.card });
      if (pm.error) { setErr(pm.error.message || "Please check your card details."); setBusy(false); return; }
      const c4 = pm.paymentMethod.card || {};
      // TEST MODE: the card was validated (tokenized — this alone moves NO money) but we
      // stop here. No sale_intent, no setup, no customer, no charge. We simulate the
      // success the flow needs so booking can proceed, with test:true on the result so
      // nothing downstream mistakes this for a real payment.
      if (!live) {
        setResult(isPay
          ? { paid: true, intentId: null, last4: c4.last4 || "••••", brand: c4.brand, test: true }
          : { saved: true, pmId: null, stripeCustomerId: null, last4: c4.last4 || "••••", brand: c4.brand, test: true });
        setBusy(false); setPhase("done");
        return;
      }
      if (isPay) {
        const dCents = Math.round(Number(amount) * 100);
        // sale-recover-succeeded: an already-succeeded deposit intent (dropped response) settles as paid.
        if (saleRef.current.clientSecret && saleRef.current.cents === dCents) {
          const recId = await recoverSucceededIntent(e.stripe, saleRef.current.clientSecret);
          if (recId) { setResult({ paid: true, intentId: recId, last4: null, brand: null }); setBusy(false); setPhase("done"); return; }
        }
        let dSecret = saleRef.current.clientSecret && saleRef.current.cents === dCents ? saleRef.current.clientSecret : null;
        if (!dSecret) {
          const intent = await stripeApi({ action: "sale_intent", amount: Number(amount), description: "Booking deposit" });
          if (!intent.clientSecret) { setErr(intent.error || "Couldn't start the charge."); setBusy(false); return; }
          dSecret = intent.clientSecret; saleRef.current = { clientSecret: dSecret, cents: dCents };
        }
        const conf = await e.stripe.confirmCardPayment(dSecret, { payment_method: pm.paymentMethod.id });
        if (conf.error) {
          if (conf.error.code === "payment_intent_unexpected_state") {
            const recId = await recoverSucceededIntent(e.stripe, dSecret);
            if (recId) { setResult({ paid: true, intentId: recId, last4: null, brand: null }); setBusy(false); setPhase("done"); return; }
            saleRef.current = { clientSecret: null, cents: null };
          }
          setErr(conf.error.message || "Your card was declined. Try a different card."); setBusy(false); return;
        }
        if (!conf.paymentIntent || conf.paymentIntent.status !== "succeeded") { setErr("The payment didn't complete. Try again."); setBusy(false); return; }
        setResult({ paid: true, intentId: conf.paymentIntent.id, last4: c4.last4 || "••••", brand: c4.brand });
      } else {
        const setup = await stripeApi({ action: "setup", customerId: null, name: clientName, email: clientEmail, phone: clientPhone });
        if (!setup.clientSecret) { setErr(setup.error || "Couldn't set up the card."); setBusy(false); return; }
        const conf = await e.stripe.confirmCardSetup(setup.clientSecret, { payment_method: pm.paymentMethod.id });
        if (conf.error) { setErr(conf.error.message || "Your card was declined. Try a different card."); setBusy(false); return; }
        setResult({ saved: true, pmId: pm.paymentMethod.id, stripeCustomerId: setup.customerId, last4: c4.last4 || "••••", brand: c4.brand });
      }
      setBusy(false); setPhase("done");
    } catch (ex) { setErr(ex.message || "Something went wrong. Please try again."); setBusy(false); }
  };

  const A = "var(--text)";
  const field = { border: "1px solid var(--border)", borderRadius: 12, background: "var(--panel)", padding: "0 13px", height: 50, display: "flex", alignItems: "center", gap: 10 };

  return (
    <Portal>
      <div onClick={close} style={{ position: "fixed", inset: 0, background: "var(--overlay, rgba(35,34,33,.45))", backdropFilter: "blur(3px)", WebkitBackdropFilter: "blur(3px)", zIndex: 4000, display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
        <div onClick={(e) => e.stopPropagation()} style={{ background: "var(--panel)", width: "100%", maxWidth: 460, borderRadius: "24px 24px 0 0", boxShadow: "0 -10px 40px rgba(40,34,22,.25)", padding: "8px 22px 26px", maxHeight: "92vh", overflowY: "auto", position: "relative" }}>
          <button onClick={close} aria-label="Close" style={{ position: "absolute", top: 12, right: 12, width: 32, height: 32, borderRadius: "50%", background: "var(--panel2)", border: "none", color: "var(--sub)", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", zIndex: 2 }}><X size={18} /></button>
          <div style={{ width: 38, height: 4, borderRadius: 3, background: "var(--border)", margin: "4px auto 14px" }} />
          {phase === "done" ? (
            <div style={{ textAlign: "center", padding: "20px 4px 10px" }}>
              <div style={{ width: 60, height: 60, borderRadius: "50%", background: "color-mix(in srgb, var(--text) 14%, transparent)", color: A, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}><Check size={30} /></div>
              <div style={{ fontFamily: "'Fraunces', serif", fontSize: 25, fontWeight: 500, marginBottom: 8 }}>{result && result.test ? (isPay ? "Deposit (test)" : "Card saved (test)") : (isPay ? "Deposit paid" : "Card saved")}</div>
              <div style={{ fontSize: 14, color: "var(--sub)", lineHeight: 1.5, marginBottom: 20 }}>
                {result && result.test
                  ? <>Test mode — no real charge was made and no card was saved. Tap below to finish this test booking.</>
                  : isPay
                  ? <>${amount} was charged and goes toward your total. Tap below to save and finish your booking.</>
                  : <>Your card is securely on file — you won't be charged unless you no-show or cancel late. Tap below to save and finish your booking.</>}
              </div>
              <button disabled={busy} onClick={() => { if (busy) return; setBusy(true); onDone && onDone(result || { saved: true, paid: isPay }); }} style={{ width: "100%", background: busy ? "var(--border2)" : A, color: "var(--bg)", border: "none", borderRadius: 13, padding: 15, fontSize: 15, fontWeight: 600, fontFamily: FONT_BODY, cursor: busy ? "default" : "pointer" }}>{busy ? "Finishing…" : "Save and finish booking"}</button>
            </div>
          ) : (
            <>
              <div style={{ fontSize: 12.5, letterSpacing: 2, color: A, fontWeight: 700, textTransform: "uppercase", marginBottom: 10 }}>{isPay ? "Deposit to reserve" : "Card to reserve"}</div>
              {isPay ? (
                <>
                  <div style={{ fontFamily: "'Fraunces', serif", fontSize: 44, fontWeight: 500, lineHeight: 1, letterSpacing: -1 }}>${amount}</div>
                  <div style={{ fontSize: 13.5, color: "var(--sub)", lineHeight: 1.5, marginTop: 8 }}>Holds your spot and goes toward your <b style={{ color: "var(--text)" }}>${totalDue}</b> total. The rest is due at your visit.</div>
                </>
              ) : (
                <div style={{ fontSize: 14, color: "var(--sub)", lineHeight: 1.5 }}>We keep a card on file to hold your spot. You won't be charged unless you no-show or cancel late.</div>
              )}

              {walletChecking && !wallet && (
                <div style={{ marginTop: 18, height: 48, borderRadius: 10, background: "var(--panel2)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, color: "var(--faint)", fontSize: 13.5 }}>
                  Checking for Apple&nbsp;Pay…
                </div>
              )}
              <div ref={prBox} style={{ marginTop: wallet ? 18 : 0 }} />
              {wallet && (
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 16 }}>
                  <div style={{ flex: 1, height: 1, background: "var(--border)" }} />
                  <span style={{ fontSize: 13, color: "var(--faint)" }}>{isPay ? "or pay with card" : "or enter your card"}</span>
                  <div style={{ flex: 1, height: 1, background: "var(--border)" }} />
                </div>
              )}

              <div style={{ marginTop: 18 }}>
                <div style={{ fontSize: 13.5, fontWeight: 600, color: "var(--text)", marginBottom: 8 }}>Enter your card</div>
                <div ref={cardBox} style={{ ...field, display: "block", paddingTop: 15 }} />
                {err && <div style={{ color: "#B5564B", fontSize: 13.5, marginTop: 8, paddingLeft: 2 }}>{err}</div>}
              </div>

              <button disabled={busy || !ready} onClick={submit} style={{ width: "100%", marginTop: 18, background: (busy || !ready) ? "var(--border2)" : A, color: "var(--bg)", border: "none", borderRadius: 13, padding: 16, fontSize: 15.5, fontWeight: 600, fontFamily: FONT_BODY, cursor: (busy || !ready) ? "default" : "pointer", boxShadow: (busy || !ready) ? "none" : "0 10px 22px -10px rgba(0,0,0,.4)" }}>{busy ? "Processing…" : (!ready ? "Loading…" : (isPay ? `Pay $${amount}` : "Save card"))}</button>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 7, marginTop: 14, fontSize: 13, color: "var(--faint)" }}><Lock size={13} /> Encrypted &amp; secure · Powered by Stripe</div>
              <button onClick={close} style={{ display: "block", width: "100%", textAlign: "center", background: "none", border: "none", color: "var(--sub)", fontSize: 13.5, marginTop: 12, cursor: "pointer", fontFamily: FONT_BODY, textDecoration: "underline", textUnderlineOffset: 3 }}>Cancel</button>
            </>
          )}
        </div>
      </div>
    </Portal>
  );
}

function PhoneLink({ number, style }) {
  const [open, setOpen] = useState(false);
  if (!number) return null;
  const clean = String(number);
  const digits = clean.replace(/\D/g, "");
  const disp = fmtPhone(clean);
  return (
    <>
      <button
        // [contact-tap] A TAP opens Call/Text. userSelect/touchCallout:none already stops the tap from
        // triggering iOS text-selection / the callout on the number, so no long-press is needed. It used
        // to REQUIRE a 450ms long-press (touchend cancelled the timer + click bailed), so a normal tap
        // did nothing — Dan: "clicking needs to do something".
        onTouchStart={(e) => e.stopPropagation()}
        onClick={(e) => { e.stopPropagation(); setOpen(true); }}
        style={{ background: "none", border: "none", color: "inherit", textDecoration: "underline", textDecorationStyle: "dotted", textDecorationColor: "var(--faint)", textUnderlineOffset: 3, padding: 0, cursor: "pointer", font: "inherit", display: "inline", userSelect: "none", WebkitUserSelect: "none", WebkitTouchCallout: "none", ...style }}>{disp}</button>
      <Sheet open={open} onClose={() => setOpen(false)} align="bottom" maxWidth={420}>
        <div style={{ padding: "6px 4px 8px", userSelect: "none", WebkitUserSelect: "none", WebkitTouchCallout: "none" }}>
          <div style={{ textAlign: "center", marginBottom: 18 }}>
            <div style={{ fontSize: 12.5, letterSpacing: 2.5, color: "var(--gold)", fontWeight: 600, marginBottom: 6 }}>CONTACT</div>
            <div style={{ fontFamily: "'Fraunces', serif", fontSize: 22, fontWeight: 500 }}>{disp}</div>
          </div>
          <a href={`tel:${digits}`} onClick={() => setOpen(false)} style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, background: "var(--gold)", color: "var(--on-gold)", padding: 16, fontSize: 14, fontWeight: 600, letterSpacing: 1.5, borderRadius: 14, textDecoration: "none", marginBottom: 10 }}>
            <Phone size={17} /> CALL
          </a>
          <a href={`sms:${digits}`} onClick={() => setOpen(false)} style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, background: "var(--panel)", color: "var(--text)", border: "1px solid var(--border)", padding: 16, fontSize: 14, fontWeight: 600, letterSpacing: 1.5, borderRadius: 14, textDecoration: "none" }}>
            <MessageSquare size={17} /> TEXT
          </a>
          <button onClick={() => setOpen(false)} style={{ width: "100%", background: "none", border: "none", color: "var(--sub)", fontSize: 14.5, padding: "12px 0 4px", marginTop: 6 }}>Cancel</button>
        </div>
      </Sheet>
    </>
  );
}

// Long-press (touch) or click (desktop) to open the device mail app, pre-addressed to the client.
