        // Preserves _categories/_cutLibrary by merging over the row we just read.
        if (biz !== rawBiz) {
          try { supabase.from('shops').upsert({ id: SHOP_ID, name: biz.name || SHOP_ID, settings: { ...shopRow.settings, ...biz } }).then(() => {}, () => {}); } catch (e) {}
        }
