        prepaidTotal: (pi === 0 && payFull && cardInfo && cardInfo.paid && typeof cardInfo.amount === "number") ? cardInfo.amount : undefined,
        prepaidTip: (pi === 0 && payFull && cardInfo && cardInfo.paid) ? (cardInfo.tip || 0) : undefined,
        prepaidIntentId: (pi === 0 && payFull && cardInfo && cardInfo.paid) ? (cardInfo.paymentIntentId || null) : undefined,
        phone: person.key === "self" ? finalPhone : ((((matched?.family || []).find((m) => m.id === person.key) || {}).phone || "").replace(/\D/g, "").length >= 10 ? ((matched?.family || []).find((m) => m.id === person.key) || {}).phone : finalPhone),
        email: (finalEmail || "").trim(), // #15: carry the booker's email on the appt so a manage-link cancel/reschedule can actually email them (email is required to book, so it's always here)
        groupId: isMultiPerson ? baseId : null,
        manageToken: makeManageToken(),
        wantsEarlier: wantEarlier,
        earlierDays: wantEarlier ? earlierPref.days : undefined,
        earlierDayTimes: wantEarlier ? earlierPref.dayTimes : undefined,
        earlierAnyProvider: wantEarlier ? !!earlierPref.anyProvider : undefined,
        newClient: (pi === 0 && bookingIsNew) ? true : undefined, // audit #29: counts toward the barber's new-client-per-day cap
        address: (pi === 0 && newAddress.trim()) ? newAddress.trim() : undefined, // #11: home address for mobile/in-home services
        discount: (pi === 0 && selfie) ? { id: "selfie", name: "Profile photo", type: "amount", value: 5 } : undefined, // $5 off for adding a profile selfie
