        lastName: (matched?.lastName || newLast || "").trim(),
        email: (finalEmail || matched?.email || "").trim(),
        phone: (finalPhone || matched?.phone || "").trim(),
        provider: matched?.provider || (newAppts[0] && newAppts[0].providerId) || "dan",
