  const snapToWorkday = (d) => {
    if (!provider) return d;
    for (let i = 0; i < 7; i++) { const t = new Date(d); t.setDate(d.getDate() + i); const h = hoursForDate(provider, t); if (h && h.on) return t; }
    return d;
  };
